import { test, expect } from '@playwright/test';

test('verify header navigation and routing', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  const header = page.locator('header');
  await expect(header).toBeVisible();

  // Verify Brand/Home link
  const homeLink = header.getByRole('link', { name: 'okwasniewski' });
  await expect(homeLink).toBeVisible();
  await homeLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Verify Portfolio link
  const portfolioLink = header.getByRole('link', { name: 'portfolio' });
  await expect(portfolioLink).toBeVisible();
  await portfolioLink.click();
  await expect(page).toHaveURL('http://localhost:3002/portfolio');

  // Verify Videos link
  const videosLink = header.getByRole('link', { name: 'videos' });
  await expect(videosLink).toBeVisible();
  await videosLink.click();
  await expect(page).toHaveURL('http://localhost:3002/videos');

  // Verify Blog link (Found to route to /blgo intermittently)
  const blogLink = header.getByRole('link', { name: 'blog' });
  await expect(blogLink).toBeVisible();
  await blogLink.click();
  await expect(page).toHaveURL('http://localhost:3002/blog');

  // Verify Contact link (Found to route to /contcat intermittently)
  const contactLink = header.getByRole('link', { name: 'contact' });
  await expect(contactLink).toBeVisible();
  await contactLink.click();
  await expect(page).toHaveURL('http://localhost:3002/contact');
});
